function ScrollRevealArrow() {
  const arrowRef = useRef(null);
  const [drawProgress, setDrawProgress] = useState(0);

  useEffect(() => {
    const el = arrowRef.current;
    if (!el) return;

    const handleScroll = () => {
      const rect = el.getBoundingClientRect();
      const windowH = window.innerHeight;
      // Start drawing when top of arrow enters bottom 80% of viewport
      // Fully drawn when the arrow's midpoint reaches 40% from top
      const raw = (windowH * 0.8 - rect.top) / (windowH * 0.55);
      setDrawProgress(Math.min(Math.max(raw, 0), 1));
    };

    window.addEventListener("scroll", handleScroll, { passive: true });
    handleScroll();
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  const scrollToNext = () => {
    const el = arrowRef.current;
    if (!el) return;
    const nextSection = el.closest("section")?.nextElementSibling;
    if (nextSection) {
      nextSection.scrollIntoView({ behavior: "smooth" });
    }
  };

  // Path length for the long curvy arrow
  const totalLength = 520;
  const dashOffset = totalLength - (drawProgress * totalLength);

  return (
    <div
      ref={arrowRef}
      onClick={scrollToNext}
      style={{
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        marginTop: 20,
        paddingBottom: 10,
        cursor: "pointer",
        height: 200,
        position: "relative",
        zIndex: 5,
      }}
    >
      <svg
        width="60"
        height="190"
        viewBox="0 0 60 190"
        fill="none"
        style={{ overflow: "visible" }}
      >
        {/* Long hand-drawn style curvy arrow that "draws" in as user scrolls */}
        <path
          d="M30 0 C30 8, 18 20, 16 40 C14 60, 38 65, 40 85 C42 105, 18 115, 20 135 C22 155, 30 170, 30 180"
          stroke={COLORS.accent}
          strokeWidth="3"
          strokeLinecap="round"
          strokeLinejoin="round"
          fill="none"
          strokeDasharray={totalLength}
          strokeDashoffset={dashOffset}
          style={{ transition: "stroke-dashoffset 0.12s ease-out" }}
        />
        {/* Arrowhead */}
        <path
          d="M20 168 L30 184 L40 168"
          stroke={COLORS.accent}
          strokeWidth="3"
          strokeLinecap="round"
          strokeLinejoin="round"
          fill="none"
          opacity={drawProgress > 0.85 ? (drawProgress - 0.85) / 0.15 : 0}
          style={{ transition: "opacity 0.2s ease-out" }}
        />
      </svg>
    </div>
  );
}



